func draftTitle(props components.DraftBlockProps) string {
	switch props.Draft.Type {
	case types.DraftTypeInitial:
		return "Initial Draft"
	case types.DraftTypeFinal:
		return "Final Draft"
	default:
		return fmt.Sprintf("Draft %d", props.Index)
	}
}

